mapper.select:
select #{incomePeriod, jdbcType = VARCHAR} as income_period, sum(sfwi.allocate_performance_pay) as allocate_performance_pay, sum(sfwi.pre_tax_withheld) as pre_tax_withheld, sum(sfwi.after_tax_withheld) as after_tax_withheld, sum(sfwi.production_factor) as production_factor, sum(sfwi.quality_factor) as quality_factor, sum(sfwi.assessment_coefficient) as assessment_coefficient from swm_floating_wage_interface sfwi where sfwi.income_period = #{incomePeriod, jdbcType = VARCHAR} and sfwi.data_status = 'T'
and sfwi.work_card in (
right(replicate('0',6) + convert(varchar(6),#{item}),6)
)
and sfwi.group_id in (
#{groupId}
)
